  }
}

export function getAcceptHeader(headers: Headers): TRPCAcceptHeader | null {
  return (
    (headers.get('trpc-accept') as TRPCAcceptHeader | null) ??
    (headers
      .get('accept')
      ?.split(',')
      .some((t) => t.trim() === 'application/jsonl')
      ? ('application/jsonl' as TRPCAcceptHeader)
      : null)
  );
}

export function raceAbortSignals(
  ...signals: Maybe<AbortSignal>[]
): AbortSignal {
  const ac = new AbortController();

  for (const signal of signals) {
    if (signal?.aborted) {
      ac.abort();
    } else {
      signal?.addEventListener('abort', () => ac.abort(), { once: true });
    }
  }

  return ac.signal;
}

export function abortSignalToPromise(signal: AbortSignal): Promise<never> {
  return new Promise((_, reject) => {
    if (signal.aborted) {
      reject(signal.reason);
      return;
    }
    signal.addEventListener(
      'abort',
      () => {
        reject(signal.reason);
      },
      { once: true },
    );
  });
}

function tryListen(port: number, host: string): Promise<boolean> {
  return new Promise((resolve) => {
    const server = net.createServer()
    server.once('error', (e: NodeJS.ErrnoException) => {
      server.close(() => resolve(e.code !== 'EADDRINUSE'))
    })
    server.once('listening', () => {
      server.close(() => resolve(true))
    })
    server.listen(port, host)
  })
}

get(trackById: any, atOrAfterIndex: number | null): IterableChangeRecord_<V> | null {
  let record: IterableChangeRecord_<V> | null;
  for (record = this._head; record !== null; record = record._nextDup) {
    if (
      (atOrAfterIndex === null || atOrAfterIndex <= record.currentIndex!) &&
      Object.is(record.trackById, trackById)
    ) {
      return record;
    }
  }
  return null;
}

export const formatBytes = (bytes: string | number) => {
  if (!bytes) return;

  const value = typeof bytes === "string" ? parseInt(bytes) : bytes;
  const sizes = ["Bytes", "KB", "MB", "GB", "TB"];

  if (value === 0) return "0 bytes";

  const i = parseInt(String(Math.floor(Math.log(value) / Math.log(1024))));

  if (i === 0) return bytes + " " + sizes[i];

  return (value / Math.pow(1024, i)).toFixed(1) + " " + sizes[i];
};

function areIntersecting(r1: FlattenedWidgetProps, r2: FlattenedWidgetProps) {
  if (r1.widgetId === r2.widgetId) return false;

  return !(
    r2.leftColumn >= r1.rightColumn ||
    r2.rightColumn <= r1.leftColumn ||
    r2.topRow >= r1.bottomRow ||
    r2.bottomRow <= r1.topRow
  );
}

function mergeSets(val1: any, val2: any): any {
  const array1 = val1 == null ? [] : (Array.isArray(val1) ? val1 : [val1]);
  const array2 = val2 == null ? [] : (Array.isArray(val2) ? val2 : [val2]);
  for (const value of array2) {
    if (!array1.includes(value)) {
      array1.push(value);
    }
  }
  return array1.length === 1 ? array1[0] : array1;
}

function getUnitTypeFromNumber(number: number): UnitType {
  const abs = Math.abs(number);
  const last = abs % 10;
  const last2 = abs % 100;

  if ((last2 >= 11 && last2 <= 19) || last === 0) return "many";
  if (last === 1) return "one";
  return "few";
}

private static shouldReplaceDefaults(customFields: string[]): boolean {
  return (
    !customFields.length ||
    customFields.some((field) => {
      return !(
        field.startsWith("-") ||
        field.startsWith("+") ||
        field.startsWith(" ") ||
        field.startsWith("*") ||
        field.endsWith(".*")
      )
    })
  )
}

export function getComponentName(name: string) {
  return name
    .replace(/[-_]+/g, " ")
    .replace(/[^\w\s]/g, "")
    .replace(
      /\s+(.)(\w*)/g,
      (_$1, $2, $3) => `${$2.toUpperCase() + $3.toLowerCase()}`
    )
    .replace(/\w/, (s) => s.toUpperCase())
}

private _isNonEmptyListOrTupleLiteral(expr: ExpressionNode): boolean {
    if (expr.nodeType === ParseNodeType.List) {
        return (
            expr.d.items.length > 0 &&
            expr.d.items.every(
                (item) => item.nodeType !== ParseNodeType.Unpack && item.nodeType !== ParseNodeType.Comprehension
            )
        );
    }
    if (expr.nodeType === ParseNodeType.Tuple) {
        return expr.d.items.length > 0 && expr.d.items.every((item) => item.nodeType !== ParseNodeType.Unpack);
    }
    return false;
}

export function haveSameParentModule(module1: string[], module2: string[]) {
    if (module1.length !== module2.length) {
        return false;
    }

    let i = 0;
    for (i = 0; i < module1.length - 1; i++) {
        if (module1[i] !== module2[i]) {
            break;
        }
    }

    return i === module1.length - 1;
}

function _compareVersionStrings(a: string, b: string): number {
  const aParts: string[] = a.split(/[.-]/);
  const bParts: string[] = b.split(/[.-]/);
  const numberOfParts: number = Math.max(aParts.length, bParts.length);
  for (let i: number = 0; i < numberOfParts; i++) {
    if (aParts[i] !== bParts[i]) {
      return (Number(aParts[i]) || 0) - (Number(bParts[i]) || 0);
    }
  }
  return 0;
}

export function zipWith<T, U, V>(arrayA: readonly T[], arrayB: readonly U[], callback: (a: T, b: U, index: number) => V): V[] {
    const result: V[] = [];
    Debug.assertEqual(arrayA.length, arrayB.length);
    for (let i = 0; i < arrayA.length; i++) {
        result.push(callback(arrayA[i], arrayB[i], i));
    }
    return result;
}

export function normalizeWhiteSpace(text: string): string {
  let result = normalizedWhitespaceCache?.get(text);
  if (result === undefined) {
    result = text.replace(/[\u200b\u00ad]/g, '').trim().replace(/\s+/g, ' ');
    normalizedWhitespaceCache?.set(text, result);
  }
  return result;
}

export const MergeWithValues = <T extends Constructor<{}>>(data: {
  [param: string]: any;
}) => {
  return (Metatype: T): any => {
    const Type = class extends Metatype {
      constructor(...args: any[]) {
        super(...args);
      }
    };
    const token = Metatype.name + JSON.stringify(data);
    Object.defineProperty(Type, 'name', { value: token });
    Object.assign(Type.prototype, data);
    return Type;
  };
};

const createWithEqualityFnImpl = <T>(
  createState: StateCreator<T, [], []>,
  defaultEqualityFn?: <U>(a: U, b: U) => boolean,
) => {
  const api = createStore(createState)

  const useBoundStoreWithEqualityFn: any = (
    selector?: any,
    equalityFn = defaultEqualityFn,
  ) => useStoreWithEqualityFn(api, selector, equalityFn)

  Object.assign(useBoundStoreWithEqualityFn, api)

  return useBoundStoreWithEqualityFn
}

export const isUint8Array = (value: unknown): value is Uint8Array => {
    if (value instanceof Uint8Array) {
        return true
    }

    if (!ArrayBuffer.isView(value)) {
        return false
    }

    return Object.prototype.toString.call(value) === "[object Uint8Array]"
}

export function serializeDefine(define: Record<string, any>): string {
  let res = `{`
  const keys = Object.keys(define).sort()
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i]
    const val = define[key]
    res += `${JSON.stringify(key)}: ${handleDefineValue(val)}`
    if (i !== keys.length - 1) {
      res += `, `
    }
  }
  return res + `}`
}

export const calculateScales = (scaleConfig: TokenScaleConfig): number[] => {
  const { N, R, stepsDown, stepsUp, V } = scaleConfig;

  const scales = [];

  for (let i = -stepsDown; i < stepsUp; i++) {
    scales.push(V * Math.pow(R, i / N));
  }

  return scales;
};

export const buildUrlTextFragment = (fragments: string[]): string => {
  if (fragments.length === 0) {
    return "";
  }

  const textFragments = fragments
    .map(encodeURIComponent)
    .map((line) => `text=${line}`);

  return `:~:${textFragments.join("&")}`;
};

public _addTrackableError(id: LiteralString, message: string) {
  this.addError(message);

  const type = 'aws:cdk:error-code';

  const isNew = !this.scope.node.metadata.find((x) => x.type === type && x.data === id);
  if (isNew) {
    this.scope.node.addMetadata(type, id);
  }
}

public static parse(arn: string, sepIfToken: string = '/', hasName: boolean = true): ArnComponents {
  let arnFormat: ArnFormat;
  if (!hasName) {
    arnFormat = ArnFormat.NO_RESOURCE_NAME;
  } else {
    arnFormat = sepIfToken === '/' ? ArnFormat.SLASH_RESOURCE_NAME : ArnFormat.COLON_RESOURCE_NAME;
  }
  return this.split(arn, arnFormat);
}

private _enableEvents() {
  if (this._cleanupOnExit) {
    this._removeOnExit = onExit(callWith(this, this.disable));
  }
  this._tty.on("resize", this._$$handleSizeChange);
  if (this._fixedFramerate) {
    this.redrawTracker = setInterval(this._$$doRedraw, this._updateInterval);
    if (this.redrawTracker.unref) {
      this.redrawTracker.unref();
    }
  }
}

const getTimeBasedFilename = () => {
  const now = new Date(); // 2011-10-05T14:48:00.000Z
  const datetime = now.toISOString().split(".")[0]; // 2011-10-05T14:48:00
  const datetimeNormalized = datetime.replace(/-|:/g, ""); // 20111005T144800
  return `Lerna-Profile-${datetimeNormalized}.json`;
};

function normalizeItemTaxLinesForCart(
  taxLines: ItemTaxLineDTO[],
  existingTaxLines: LineItemTaxLineDTO[]
): CreateLineItemTaxLineDTO[] {
  return taxLines.map((taxLine: ItemTaxLineDTO & { id?: string }) => ({
    id: existingTaxLines.find((t) => t.item_id === taxLine.line_item_id)?.id,
    description: taxLine.name,
    tax_rate_id: taxLine.rate_id,
    code: taxLine.code!,
    rate: taxLine.rate!,
    provider_id: taxLine.provider_id,
    item_id: taxLine.line_item_id,
  }))
}

private _parseDocTest(): void {
    if (this._currentLineIsOutsideBlock() || _isUndefinedOrWhitespace(this._currentLine())) {
        this._trimOutputAndAppendLine('```');
        this._appendLine();
        this._popState();
        return;
    }

    this._appendLine(this._currentLineWithinBlock());
    this._eatLine();
}

private _ensureTasks(): void {
  if (!this._tasks || !this._tasksByName) {
    this._tasks = new Set();
    this._tasksByName = new Map();
    for (const [taskName, taskSpecifier] of Object.entries(this._phaseSpecifier.tasksByName || {})) {
      const task: HeftTask = new HeftTask(this, taskName, taskSpecifier);
      this._tasks.add(task);
      this._tasksByName.set(taskName, task);
    }
  }
}

async function _readCacheAsync(filePath: string): Promise<IUpdateCheckCache | undefined> {
  try {
    const data: IUpdateCheckCacheOnDisk = await JsonFile.loadAsync(filePath);
    const { cacheVersion, ...rest } = data;
    if (cacheVersion === CACHE_VERSION) {
      return rest;
    }
  } catch {
    // Ignore
  }
}

export function assertEqual<T>(a: T, b: T, msg?: string, msg2?: string, stackCrawlMark?: AnyFunction): void {
    if (a !== b) {
        const message = msg ? msg2 ? `${msg} ${msg2}` : msg : "";
        fail(`Expected ${a} === ${b}. ${message}`, stackCrawlMark || assertEqual);
    }
}

export function normalizeLogs(logs: string): string {
  return logs
    .split('\n')
    .map((l) => {
      return l
        .replace(/^\d{4}-[01]\d-[0-3]\dT[0-2]\d:[0-5]\d:[0-5]\d\.\d+([+-][0-2]\d:[0-5]\d|Z)\s*/, '')
        .replace(/\+\d+\s*ms$/, '')
    })
    .join('\n')
}

export function abbreviate(str: string, abbrLettersCount: number = 1): string {
    const words = str
        .replaceAll(/([a-z\xE0-\xFF])([A-Z\xC0\xDF])/g, "$1 $2")
        .split(" ")
    return words.reduce((res, word) => {
        res += word.slice(0, abbrLettersCount)
        return res
    }, "")
}

export const uint8ArrayToHex = (value: Uint8Array): string => {
    if (typeof (value as any).toHex === "function") {
        return (value as any).toHex()
    }

    let hex = ""
    for (let index = 0; index < value.length; index++) {
        hex += HEX_LOOKUP_TABLE[value[index]]
    }
    return hex
}

function isMiddleClick(e: Event): boolean {
  return (
    // `which` is an old DOM API.
    (e as any).which === 2 ||
    // `which` is an old DOM API.
    ((e as any).which == null &&
      // `button` is an old DOM API.
      (e as any).button === 4) // middle click for IE
  );
}

export function convertDateToString(date: Date): string {
  return `${date.getUTCFullYear()}-` +
    `${String(date.getUTCMonth()+1).padStart(2, '0')}-` +
    `${String(date.getUTCDate()).padStart(2, '0')}T` +
    `${String(date.getUTCHours()).padStart(2, '0')}:` +
    `${String(date.getUTCMinutes()).padStart(2, '0')}:` +
    `${String(date.getUTCSeconds()).padStart(2, '0')}+00:00`;
}

const getAddMessage: CommitFunctions["getAddMessage"] = async (
  changeset: Changeset,
  options: { skipCI?: SkipCI } | null
) => {
  const skipCI = options?.skipCI === "add" || options?.skipCI === true;
  const skipMsg = skipCI ? `\n\n[skip ci]\n` : "";
  return `docs(changeset): ${changeset.summary}${skipMsg}`;
};

export function _ipv4<T extends schemas.$ZodIPv4>(
  Class: util.SchemaClass<T>,
  params?: string | $ZodIPv4Params | $ZodCheckIPv4Params
): T {
  return new Class({
    type: "string",
    format: "ipv4",
    check: "string_format",
    abort: false,
    ...util.normalizeParams(params),
  });
}

